#include <bits/stdc++.h>
using namespace std;
using namespace std::chrono;
#define ll long long
#define endl '\n'

int numSpecial(vector<vector<int>>& mat) {
        int m = mat.size();
        int n = mat[0].size(), special = 0;
        vector<pair<int,int>> point;
        for(int i = 0; i<m ;++i)
            for(int j=0;j<n;j++)
                if(mat[i][j]==1)
                    point.push_back({i,j});
        
        for(auto p: point){
            int x = p.first;
            int y = p.second;
            int cnt = 0;
            for(int i=0;i<n;++i)
                if(mat[x][i]==1)
                    ++cnt;
            for(int i=0;i<m;++i)
                if(mat[i][y]==1)
                    ++cnt;
            if(cnt==2)
                ++special;
        }
        return special;
        
    }

